boot.artifact:
// inferred-not-tested:artifact 列 H0 探针未闭合;本版本为 prerelease,必须完整固定
import initRDKitModule from 'https://cdn.jsdelivr.net/npm/@rdkit/rdkit@2025.3.4-1.0.0/+esm';
const wasm = 'https://cdn.jsdelivr.net/npm/@rdkit/rdkit@2025.3.4-1.0.0/dist/RDKit_minimal.wasm';
const RDKit = await initRDKitModule({ locateFile: () => wasm });
const el = document.getElementById('molecule'); el.style.height = '320px';
const mol = RDKit.get_mol(data.source); if (!mol) throw new Error('RDKit 无法解析 source');
try { el.innerHTML = mol.get_svg(el.clientWidth || 480, 320); } finally { mol.delete(); }

boot.widget:
// WASM 与 JS 固定同一完整版本;输出 SVG 落 shadow 容器
import initRDKitModule from 'https://cdn.jsdelivr.net/npm/@rdkit/rdkit@2025.3.4-1.0.0/+esm';
const RDKit = await initRDKitModule({ locateFile: () => 'https://cdn.jsdelivr.net/npm/@rdkit/rdkit@2025.3.4-1.0.0/dist/RDKit_minimal.wasm' });
const el = document.createElement('div'); el.style.height = '320px'; shadowRoot.appendChild(el);
const mol = RDKit.get_mol(data.source); if (!mol) throw new Error('RDKit 无法解析 source');
try { el.innerHTML = mol.get_svg(el.clientWidth || 480, 320); } finally { mol.delete(); }
